def QZ(mod,t,s,qs):
    les=Lesson.objects.create(module=mod, title=t, description='', content_type=Lesson.ContentType.QUIZ, content_body='', duration_minutes=5, status=Lesson.Status.PUBLISHED, sort_order=s)
    for i,q in enumerate(qs): Question.objects.create(lesson=les, question_text=q[0], option_a=q[1], option_b=q[2], option_c=q[3], option_d=q[4], correct_option=q[5], sort_order=i+1)

