def add_sem(yr, sem_num, name, courses_list):
    sem = Semester.objects.create(program_id=prog_id, year_number=yr, semester_number=sem_num, name=name)
    print(f'\n{name} (sem={sem.id})')
    for title, desc, topics, proj_title, proj_steps, qk, diff in courses_list:
        p = LearningPath.objects.create(title=title, description=desc, status=LearningPath.Status.PUBLISHED, difficulty=diff, estimated_hours=0, instructor_id=instructor_id, semester=sem)
        for i, t in enumerate(topics, 1):
            mod = M(p, t, i)
            L(mod, f'Introduction to {t}', 1)
            L(mod, f'Core Concepts in {t}', 2)
            L(mod, f'Practical {t} Techniques', 3)
            L(mod, f'{t} Best Practices', 4)
            QZ(mod, f'{t} Quiz', 5, G[qk])
        mod = M(p, f'Project: {proj_title}', len(topics)+1)
        for j, s in enumerate(proj_steps, 1):
            L(mod, s, j)
        QZ(mod, f'{proj_title} Project Quiz', len(proj_steps)+1, G[qk])
        p.estimated_hours = round((len(topics)*(4*10+5) + (len(proj_steps)*10+5))/60)
        p.save(update_fields=['estimated_hours'])
        print(f'  {p.id}: {title}')

